public class RevLL{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode reverse(ListNode head){ListNode prev=null,curr=head,next;while(curr!=null){next=curr.next;curr.next=prev;prev=curr;curr=next;}return prev;}
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    public static void main(String[] a){System.out.println(str(reverse(of(1,2,3,4,5))));System.out.println(str(reverse(of(1,2))));System.out.println("O(n) O(1): 3-pointer prev/curr/next");}
}

public class RevBetween{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode reverseBetween(ListNode head,int left,int right){ListNode dummy=new ListNode(0);dummy.next=head;ListNode prev=dummy;for(int i=0;i<left-1;i++)prev=prev.next;ListNode curr=prev.next,prevNode=null,nextNode;int steps=right-left+1;ListNode tail=curr;for(int i=0;i<steps;i++){nextNode=curr.next;curr.next=prevNode;prevNode=curr;curr=nextNode;}prev.next=prevNode;tail.next=curr;return dummy.next;}
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
