public class RotLL{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode rotateRight(ListNode head,int k){if(head==null||k==0)return head;int len=1;ListNode tail=head;while(tail.next!=null){tail=tail.next;len++;}k%=len;if(k==0)return head;tail.next=head;ListNode prev=head;for(int i=0;i<len-k-1;i++)prev=prev.next;ListNode newHead=prev.next;prev.next=null;tail.next=null; return newHead;}
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
